#!/usr/bin/env node
// Phase A spike — verify HOME-redirect approach for runner-owned sessions.
// Design doc: docs/plans/2026-04-29-runner-owned-sessions-design.md, §D1.
//
// Goal: confirm that setting HOME to a temp path causes the SDK to write its
// jsonl session file inside that temp tree, and that query({ resume }) can
// pick up context from the prior turn against the same redirected HOME.
//
// Run from the package dir so the SDK dep resolves:
//   cd packages/agent-claude-sdk-runner
//   ANTHROPIC_API_KEY=sk-ant-... node spike-home-redirect.mjs
//
// Throwaway. Not wired into build, not committed to source.

import { mkdirSync, mkdtempSync, readFileSync, readdirSync, statSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, relative, sep } from 'node:path';

// Set HOME BEFORE importing the SDK, in case the SDK captures os.homedir() at
// import time. (It doesn't appear to in 0.2.119, but cheap insurance.)
const tempHome = mkdtempSync(join(tmpdir(), 'spike-home-'));
const tempCwd = mkdtempSync(join(tmpdir(), 'spike-cwd-'));
process.env.HOME = tempHome;

console.log('---- Phase A spike ----');
console.log('HOME    :', tempHome);
console.log('cwd     :', tempCwd);

if (!process.env.ANTHROPIC_API_KEY) {
  console.error('Missing ANTHROPIC_API_KEY — spike requires a real key.');
  process.exit(2);
}

const { query } = await import('@anthropic-ai/claude-agent-sdk');

const MAGIC_PHRASE = 'PURPLE-OWL-42';
const TURN1_PROMPT = `Please remember this phrase exactly so you can repeat it later: "${MAGIC_PHRASE}". Then reply with only the word "noted".`;
const TURN2_PROMPT = `What was the phrase I asked you to remember earlier? Reply with only the phrase itself, nothing else.`;

const sharedOptions = {
  cwd: tempCwd,
  // Match production runner isolation: no ~/.claude/CLAUDE.md, no project
  // settings, no user prefs. This is what the actual runner ships with.
  settingSources: [],
  // Cheap + fast for the spike. Real one-shot completion, not enough turns
  // to matter cost-wise.
  model: 'claude-haiku-4-5-20251001',
  // Don't let it try to use tools.
  allowedTools: [],
  permissionMode: 'bypassPermissions',
};

function listAllFiles(root) {
  const out = [];
  function walk(dir) {
    let entries;
    try {
      entries = readdirSync(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const ent of entries) {
      const full = join(dir, ent.name);
      if (ent.isDirectory()) {
        walk(full);
      } else if (ent.isFile() || ent.isSymbolicLink()) {
        let size = 0;
        try { size = statSync(full).size; } catch {}
        out.push({ rel: relative(root, full), bytes: size });
      }
    }
  }
  walk(root);
  return out.sort((a, b) => a.rel.localeCompare(b.rel));
}

async function runTurn(label, opts) {
  console.log(`\n---- ${label} ----`);
  let sessionId;
  let assistantText = '';
  const iter = query(opts);
  for await (const msg of iter) {
    if (msg.type === 'system' && msg.subtype === 'init') {
      sessionId = msg.session_id ?? msg.sessionId;
      console.log(`[init] session_id=${sessionId}`);
    }
    if (msg.type === 'assistant') {
      const text = (msg.message?.content ?? [])
        .flatMap((b) => (b.type === 'text' ? [b.text] : []))
        .join('\n');
      if (text.length > 0) assistantText += text;
    }
    if (msg.type === 'result') {
      console.log(`[result] subtype=${msg.subtype} dur_ms=${msg.duration_ms ?? '?'} cost_usd=${msg.total_cost_usd ?? '?'}`);
    }
  }
  console.log(`[assistant text] ${JSON.stringify(assistantText)}`);
  return { sessionId, assistantText };
}

// ---- Turn 1: fresh session, no resume ----
const turn1 = await runTurn('Turn 1 (fresh session)', {
  prompt: TURN1_PROMPT,
  options: { ...sharedOptions },
});

if (!turn1.sessionId) {
  console.error('No sessionId captured from turn 1; aborting.');
  process.exit(3);
}

// ---- Inspect HOME tree after turn 1 ----
console.log('\n---- HOME tree after turn 1 ----');
const filesAfter1 = listAllFiles(tempHome);
for (const f of filesAfter1) {
  console.log(`  ${f.rel}  (${f.bytes} bytes)`);
}

// Predicted jsonl path: <HOME>/.claude/projects/<sanitized-cwd>/<sessionId>.jsonl
const sanitizedCwd = tempCwd.split(sep).join('-');
const predictedJsonl = join(tempHome, '.claude', 'projects', sanitizedCwd, `${turn1.sessionId}.jsonl`);
console.log('\n[predict] expected jsonl path:', predictedJsonl);

let actualJsonl = filesAfter1.find((f) => f.rel.endsWith(`${turn1.sessionId}.jsonl`));
if (actualJsonl) {
  const actualAbs = join(tempHome, actualJsonl.rel);
  console.log('[match]   actual jsonl path  :', actualAbs);
  console.log('[match]   matches prediction :', actualAbs === predictedJsonl);
  // Show the first few lines to sanity-check format.
  const head = readFileSync(actualAbs, 'utf8').split('\n').slice(0, 4).join('\n');
  console.log('[head]\n' + head.split('\n').map((l) => '  ' + l.slice(0, 200)).join('\n'));
} else {
  console.error('[ERROR] No jsonl found containing sessionId in HOME tree.');
}

// ---- Turn 2: resume the same session ----
const turn2 = await runTurn('Turn 2 (resume)', {
  prompt: TURN2_PROMPT,
  options: { ...sharedOptions, resume: turn1.sessionId },
});

console.log('\n---- Verdict ----');
const recalled = turn2.assistantText.includes(MAGIC_PHRASE);
console.log(`[resume] turn 2 sessionId    : ${turn2.sessionId}`);
console.log(`[resume] same as turn 1?     : ${turn2.sessionId === turn1.sessionId}`);
console.log(`[resume] recalled magic phrase: ${recalled}`);

