55	  title: string | null;
56	  /** Nullable; cleared in Task 14. */
57	  activeSessionId: string | null;
58	  /** Nullable; the in-flight reqId, if any (Invariant J7). */
59	  activeReqId: string | null;
60	  /** ISO-8601 string. */
61	  createdAt: string;
62	  /** ISO-8601 string. */
63	  updatedAt: string;
64	}
65	
66	// ---------------------------------------------------------------------------
67	// Service hook payloads.
68	//
69	// Every hook is gated by a `agents:resolve(agentId, userId)` call BEFORE
70	// touching the store (Invariant J1). On `forbidden` / `not-found` from
71	// `agents:resolve` we propagate the matching `PluginError` code.
72	// ---------------------------------------------------------------------------
73	
74	export interface CreateInput {
75	  userId: string;
76	  agentId: string;
77	  /** Optional title — MVP leaves it null. */
78	  title?: string | null;
79	}
