248	      // index covers (user_id, agent_id) — adding active_req_id to the
249	      // WHERE clause is still cheap because user_id alone narrows to a
250	      // single user's rowset.
251	      const row = await db
252	        .selectFrom('conversations_v1_conversations')
253	        .selectAll('conversations_v1_conversations')
254	        .where('user_id', '=', userId)
255	        .where('active_req_id', '=', reqId)
