272	        .selectFrom('conversations_v1_turns')
273	        .selectAll('conversations_v1_turns')
274	        .where('conversation_id', '=', conversationId)
275	        .orderBy('turn_index', 'asc')
276	        .execute();
277	      return rows.map(rowToTurn);
278	    },
279	
280	    async create({ userId, agentId, title }) {
281	      const id = mintConversationId();
282	      const now = new Date();
283	      const row = await db
284	        .insertInto('conversations_v1_conversations')
285	        .values({
286	          conversation_id: id,
287	          user_id: userId,
288	          agent_id: agentId,
289	          title,
290	          active_session_id: null,
291	          active_req_id: null,
292	          deleted_at: null,
293	          created_at: now,
294	          updated_at: now,
295	        })
296	        .returningAll()
297	        .executeTakeFirstOrThrow();
298	      return rowToConversation(row as ConversationsRow);
299	    },
300	
301	    async appendTurn({ conversationId, role, contentBlocks }) {
302	      // Compute turn_index inside a transaction with row-level locking on
303	      // the conversation row. Concurrent inserts on the same conversation
304	      // serialize through SELECT ... FOR UPDATE, so the UNIQUE(
305	      // conversation_id, turn_index) constraint can never trip — the
306	      // index lookup, mint, and insert all happen under the lock.
307	      return await db.transaction().execute(async (trx) => {
308	        // Lock the conversation row to serialize appendTurn calls for
309	        // this conversation. Reading + write happen inside the same tx
310	        // so isolation is consistent.
311	        //
312	        // The `deleted_at IS NULL` filter closes a TOCTOU window: a
313	        // concurrent softDelete landing between the plugin's pre-check
314	        // (`getByIdNotDeleted`) and the FOR UPDATE acquisition would
315	        // otherwise let turns slip into a tombstoned conversation.
316	        // executeTakeFirstOrThrow → NoResultError surfaces as a
317	        // PluginError('not-found') in the plugin layer.
318	        await trx
319	          .selectFrom('conversations_v1_conversations')
320	          .select('conversation_id')
321	          .where('conversation_id', '=', conversationId)
322	          .where('deleted_at', 'is', null)
323	          .forUpdate()
324	          .executeTakeFirstOrThrow();
325	
326	        const lastRow = await trx
327	          .selectFrom('conversations_v1_turns')
328	          .select('turn_index')
329	          .where('conversation_id', '=', conversationId)
330	          .orderBy('turn_index', 'desc')
331	          .limit(1)
332	          .executeTakeFirst();
333	        const nextIndex = lastRow === undefined ? 0 : lastRow.turn_index + 1;
334	
335	        const id = mintTurnId();
336	        const now = new Date();
337	        const row = await trx
338	          .insertInto('conversations_v1_turns')
339	          .values({
340	            turn_id: id,
341	            conversation_id: conversationId,
342	            turn_index: nextIndex,
343	            role,
344	            // Kysely's pg dialect serializes JSONB on the way down; pass
345	            // the array directly via JSON.stringify (matches @ax/agents
346	            // store pattern for allowed_tools).
347	            content_blocks: JSON.stringify(contentBlocks) as unknown,
348	            created_at: now,
349	          } as never)
350	          .returningAll()
351	          .executeTakeFirstOrThrow();
352	
353	        // Touch updated_at on the parent row so list orderings stay
354	        // sensible. Stays inside the same tx.
355	        await trx
356	          .updateTable('conversations_v1_conversations')
357	          .set({ updated_at: now })
358	          .where('conversation_id', '=', conversationId)
359	          .execute();
360	
361	        return rowToTurn(row as TurnsRow);
362	      });
363	    },
364	
365	    async softDelete(conversationId) {
366	      const result = await db
367	        .updateTable('conversations_v1_conversations')
368	        .set({ deleted_at: new Date(), updated_at: new Date() })
369	        .where('conversation_id', '=', conversationId)
370	        .where('deleted_at', 'is', null)
371	        .executeTakeFirst();
372	      return Number(result.numUpdatedRows ?? 0n) > 0;
373	    },
374	
375	    async setActiveSession({ conversationId, userId, sessionId, reqId }) {
376	      // Filter by user_id alongside conversation_id so a foreign caller
377	      // can never bind a row they don't own. Non-existence + foreign-user
378	      // both look identical from the caller's perspective: numUpdatedRows
379	      // === 0 → 'not-found' at the plugin layer.
380	      const result = await db
381	        .updateTable('conversations_v1_conversations')
382	        .set({
383	          active_session_id: sessionId,
384	          active_req_id: reqId,
385	          updated_at: new Date(),
386	        })
387	        .where('conversation_id', '=', conversationId)
388	        .where('user_id', '=', userId)
389	        .where('deleted_at', 'is', null)
390	        .executeTakeFirst();
391	      return Number(result.numUpdatedRows ?? 0n) > 0;
392	    },
393	
394	    async clearActiveSession({ conversationId, userId }) {
395	      const result = await db
396	        .updateTable('conversations_v1_conversations')
397	        .set({
398	          active_session_id: null,
399	          active_req_id: null,
400	          updated_at: new Date(),
401	        })
402	        .where('conversation_id', '=', conversationId)
403	        .where('user_id', '=', userId)
404	        .where('deleted_at', 'is', null)
405	        .executeTakeFirst();
406	      return Number(result.numUpdatedRows ?? 0n) > 0;
407	    },
408	
409	    async clearActiveReqId(conversationId, expectedReqId) {
410	      // Compare-and-clear on `active_req_id`. If a fresh reqId has already
411	      // been bound (e.g. a second user message arrived between this turn-
412	      // end being fired and the subscriber running), the WHERE will miss
413	      // and the newer in-flight reqId is preserved. This is essential for
414	      // J6's "no stale clobber" property.
415	      const result = await db
416	        .updateTable('conversations_v1_conversations')
417	        .set({ active_req_id: null, updated_at: new Date() })
418	        .where('conversation_id', '=', conversationId)
419	        .where('active_req_id', '=', expectedReqId)
420	        .where('deleted_at', 'is', null)
421	        .executeTakeFirst();
422	      return Number(result.numUpdatedRows ?? 0n) > 0;
423	    },
424	
425	    async clearBySessionId(sessionId) {
426	      // No user_id filter — host-internal observation of a sandbox
427	      // teardown. We clear active_session_id AND active_req_id together
428	      // because if the session is gone, an in-flight reqId pointing at
429	      // it is dead too.
430	      const result = await db
431	        .updateTable('conversations_v1_conversations')
432	        .set({
433	          active_session_id: null,
434	          active_req_id: null,
435	          updated_at: new Date(),
436	        })
437	        .where('active_session_id', '=', sessionId)
438	        .where('deleted_at', 'is', null)
439	        .executeTakeFirst();
440	      return Number(result.numUpdatedRows ?? 0n);
441	    },
442	  };
443	}
