  displayName: string;
  systemPrompt: string;
  allowedTools: string[];
  mcpConfigIds: string[];
  model: string;
  workspaceRef: string | null;
  visibility: 'personal' | 'team';
  teamId: string | null;
}

export function validateCreateInput(
  input: AgentInput,
  vctx: ValidationContext,
): ValidatedAgentInput {
  const visibility = validateVisibility(input.visibility);
